SELECT p.id, p.post_title, p.score, p.view_count, p.answer_count, p.creation_date, u.id AS author_id, u.display_name, u.reputation FROM posts AS p LEFT JOIN users AS u ON u.id = p.owner_user_id WHERE p.creation_date >= '2009-04-01' AND p.creation_date < '2009-07-01' AND p.post_type_id = 1 ORDER BY p.score DESC, p.view_count DESC LIMIT 100;
SELECT q.id AS question_id, q.post_title, q.score AS question_score, qu.display_name AS question_author, a.id AS answer_id, a.score AS answer_score, au.display_name AS answer_author FROM posts AS q JOIN posts AS a ON a.id = q.accepted_answer_id LEFT JOIN users AS qu ON qu.id = q.owner_user_id LEFT JOIN users AS au ON au.id = a.owner_user_id WHERE q.creation_date >= '2009-04-01' AND q.creation_date < '2009-07-01' AND q.post_type_id = 1 AND q.accepted_answer_id IS NOT NULL ORDER BY q.score DESC LIMIT 100;
SELECT q.id AS question_id, q.post_title, q.score AS question_score, qu.display_name AS question_author, a.id AS answer_id, a.score AS answer_score, au.display_name AS answer_author FROM posts AS q JOIN posts AS a ON a.id = q.accepted_answer_id LEFT JOIN users AS qu ON qu.id = q.owner_user_id LEFT JOIN users AS au ON au.id = a.owner_user_id WHERE q.creation_date >= '2009-04-01' AND q.creation_date < '2009-07-01' AND a.creation_date >= '2009-04-01' AND a.creation_date < '2009-07-01' AND q.post_type_id = 1 ORDER BY q.score DESC LIMIT 100;
SELECT a.id AS answer_id, a.score AS answer_score, au.display_name AS answer_author, q.id AS question_id, q.post_title, q.score AS question_score, qu.display_name AS question_author FROM posts AS a JOIN posts AS q ON q.id = a.parent_id LEFT JOIN users AS au ON au.id = a.owner_user_id LEFT JOIN users AS qu ON qu.id = q.owner_user_id WHERE a.creation_date >= '2009-04-01' AND a.creation_date < '2009-07-01' AND a.post_type_id = 2 ORDER BY a.score DESC LIMIT 100;
SELECT a.id AS answer_id, a.score AS answer_score, au.display_name AS answer_author, q.id AS question_id, q.post_title, q.score AS question_score, qu.display_name AS question_author FROM posts AS a JOIN posts AS q ON q.id = a.parent_id LEFT JOIN users AS au ON au.id = a.owner_user_id LEFT JOIN users AS qu ON qu.id = q.owner_user_id WHERE a.creation_date >= '2009-04-01' AND a.creation_date < '2009-07-01' AND q.creation_date >= '2009-04-01' AND q.creation_date < '2009-07-01' AND a.post_type_id = 2 ORDER BY a.score DESC LIMIT 100;
SELECT u.id, u.display_name, u.reputation, COUNT(*) AS question_count, SUM(p.score) AS total_score, AVG(p.view_count) AS avg_views, SUM(p.answer_count) AS total_answers FROM posts AS p JOIN users AS u ON u.id = p.owner_user_id WHERE p.creation_date >= '2009-04-01' AND p.creation_date < '2009-07-01' AND p.post_type_id = 1 GROUP BY u.id, u.display_name, u.reputation HAVING COUNT(*) >= 3 ORDER BY total_score DESC, question_count DESC LIMIT 100;
SELECT u.id, u.display_name, u.reputation, COUNT(*) AS question_count, SUM(p.score) AS total_score, AVG(p.view_count) AS avg_views, SUM(p.answer_count) AS total_answers FROM posts AS p JOIN users AS u ON u.id = p.owner_user_id WHERE p.creation_date >= '2009-01-01' AND p.creation_date < '2010-01-01' AND p.post_type_id = 1 GROUP BY u.id, u.display_name, u.reputation HAVING COUNT(*) >= 5 ORDER BY total_score DESC, question_count DESC LIMIT 100;
SELECT DATE(p.creation_date) AS day, COUNT(*) AS question_count, COUNT(DISTINCT u.id) AS active_authors, SUM(p.score) AS total_score, AVG(p.view_count) AS avg_views, SUM(p.answer_count) AS answer_count FROM posts AS p LEFT JOIN users AS u ON u.id = p.owner_user_id WHERE p.creation_date >= '2009-04-01' AND p.creation_date < '2009-07-01' AND p.post_type_id = 1 GROUP BY DATE(p.creation_date) ORDER BY day;
SELECT p.id, p.post_title, p.post_type_id, p.score, p.creation_date, owner.display_name AS owner_name, editor.display_name AS editor_name, p.last_edit_date FROM posts AS p LEFT JOIN users AS owner ON owner.id = p.owner_user_id LEFT JOIN users AS editor ON editor.id = p.last_editor_user_id WHERE p.creation_date >= '2009-04-01' AND p.creation_date < '2009-07-01' AND p.last_editor_user_id IS NOT NULL ORDER BY p.last_edit_date DESC LIMIT 100;
SELECT u.id, u.display_name, SUM(p.post_type_id = 1) AS question_count, SUM(p.post_type_id = 2) AS answer_count, SUM(p.score) AS total_score, AVG(p.score) AS avg_score FROM users AS u JOIN posts AS p ON p.owner_user_id = u.id WHERE p.creation_date >= '2009-04-01' AND p.creation_date < '2009-07-01' GROUP BY u.id, u.display_name HAVING COUNT(*) >= 5 ORDER BY total_score DESC LIMIT 100;
WITH daily_author_stats AS (SELECT DATE(p.creation_date) AS day, p.owner_user_id, COUNT(*) AS post_count, SUM(p.score) AS total_score FROM posts AS p WHERE p.creation_date >= '2009-04-01' AND p.creation_date < '2009-07-01' AND p.owner_user_id IS NOT NULL GROUP BY DATE(p.creation_date), p.owner_user_id), ranked AS (SELECT day, owner_user_id, post_count, total_score, DENSE_RANK() OVER (PARTITION BY day ORDER BY total_score DESC) AS score_rank FROM daily_author_stats) SELECT r.day, r.score_rank, u.id, u.display_name, r.post_count, r.total_score FROM ranked AS r JOIN users AS u ON u.id = r.owner_user_id WHERE r.score_rank <= 10 ORDER BY r.day, r.score_rank;
WITH author_stats AS (SELECT p.owner_user_id, COUNT(*) AS post_count, SUM(p.score) AS total_score, AVG(p.view_count) AS avg_views FROM posts AS p WHERE p.creation_date >= '2009-04-01' AND p.creation_date < '2009-07-01' AND p.owner_user_id IS NOT NULL GROUP BY p.owner_user_id) SELECT u.id, u.display_name, a.post_count, a.total_score, a.avg_views, DENSE_RANK() OVER (ORDER BY a.total_score DESC) AS score_rank, DENSE_RANK() OVER (ORDER BY a.post_count DESC) AS activity_rank FROM author_stats AS a JOIN users AS u ON u.id = a.owner_user_id ORDER BY score_rank LIMIT 100;
SELECT YEAR(p.creation_date) AS year_number, MONTH(p.creation_date) AS month_number, u.id, u.display_name, COUNT(*) AS post_count, SUM(p.score) AS total_score FROM posts AS p JOIN users AS u ON u.id = p.owner_user_id WHERE p.creation_date >= '2009-01-01' AND p.creation_date < '2010-01-01' GROUP BY YEAR(p.creation_date), MONTH(p.creation_date), u.id, u.display_name HAVING COUNT(*) >= 5 ORDER BY year_number, month_number, total_score DESC LIMIT 500;
SELECT q.id AS question_id, q.post_title, q.score AS question_score, a.id AS accepted_answer_id, a.score AS answer_score, a.score - q.score AS score_difference, qu.display_name AS question_author, au.display_name AS answer_author FROM posts AS q JOIN posts AS a ON a.id = q.accepted_answer_id LEFT JOIN users AS qu ON qu.id = q.owner_user_id LEFT JOIN users AS au ON au.id = a.owner_user_id WHERE q.creation_date >= '2009-04-01' AND q.creation_date < '2009-07-01' AND a.creation_date >= '2009-04-01' AND a.creation_date < '2009-10-01' AND q.post_type_id = 1 ORDER BY score_difference DESC LIMIT 100;
SELECT au.id, au.display_name, COUNT(*) AS accepted_answer_count, SUM(a.score) AS accepted_answer_score, AVG(a.score) AS avg_accepted_answer_score, COUNT(DISTINCT q.owner_user_id) AS distinct_question_authors FROM posts AS q JOIN posts AS a ON a.id = q.accepted_answer_id JOIN users AS au ON au.id = a.owner_user_id WHERE q.creation_date >= '2009-04-01' AND q.creation_date < '2009-07-01' AND a.creation_date >= '2009-04-01' AND a.creation_date < '2009-10-01' GROUP BY au.id, au.display_name HAVING COUNT(*) >= 2 ORDER BY accepted_answer_count DESC, accepted_answer_score DESC LIMIT 100;
WITH candidate_posts AS (SELECT p.id, p.owner_user_id, p.post_title, p.score, p.comment_count FROM posts AS p WHERE p.creation_date >= '2009-04-01' AND p.creation_date < '2009-07-01' AND p.post_type_id = 1 ORDER BY p.score DESC LIMIT 1000), comment_stats AS (SELECT c.post_id, COUNT(*) AS real_comment_count, COUNT(DISTINCT c.user_id) AS commenter_count, AVG(c.score) AS avg_comment_score, MAX(c.creation_date) AS last_comment_date FROM comments AS c JOIN candidate_posts AS cp ON cp.id = c.post_id GROUP BY c.post_id) SELECT cp.id, cp.post_title, cp.score, u.display_name, cp.comment_count AS stored_comment_count, cs.real_comment_count, cs.commenter_count, cs.avg_comment_score, cs.last_comment_date FROM candidate_posts AS cp LEFT JOIN comment_stats AS cs ON cs.post_id = cp.id LEFT JOIN users AS u ON u.id = cp.owner_user_id ORDER BY cs.real_comment_count DESC, cp.score DESC LIMIT 100;
WITH candidate_posts AS (SELECT p.id, p.owner_user_id, p.post_title, p.score FROM posts AS p WHERE p.creation_date >= '2009-04-01' AND p.creation_date < '2009-07-01' AND p.post_type_id = 1 ORDER BY p.score DESC LIMIT 1000), vote_stats AS (SELECT v.post_id, COUNT(*) AS vote_count, SUM(v.vote_type_id = 2) AS type_2_votes, SUM(v.vote_type_id = 3) AS type_3_votes, COUNT(DISTINCT v.vote_type_id) AS vote_type_count FROM votes AS v JOIN candidate_posts AS cp ON cp.id = v.post_id GROUP BY v.post_id) SELECT cp.id, cp.post_title, cp.score, u.display_name, vs.vote_count, vs.type_2_votes, vs.type_3_votes, vs.vote_type_count FROM candidate_posts AS cp LEFT JOIN vote_stats AS vs ON vs.post_id = cp.id LEFT JOIN users AS u ON u.id = cp.owner_user_id ORDER BY vs.vote_count DESC, cp.score DESC LIMIT 100;
WITH candidate_posts AS (SELECT p.id, p.owner_user_id, p.post_title, p.score FROM posts AS p WHERE p.creation_date >= '2009-04-01' AND p.creation_date < '2009-07-01' AND p.post_type_id = 1 ORDER BY p.score DESC LIMIT 1000), history_stats AS (SELECT ph.post_id, COUNT(*) AS revision_count, COUNT(DISTINCT ph.user_id) AS editor_count, COUNT(DISTINCT ph.post_history_type_id) AS history_type_count, MAX(ph.creation_date) AS last_revision FROM post_history AS ph JOIN candidate_posts AS cp ON cp.id = ph.post_id GROUP BY ph.post_id) SELECT cp.id, cp.post_title, cp.score, u.display_name, hs.revision_count, hs.editor_count, hs.history_type_count, hs.last_revision FROM candidate_posts AS cp LEFT JOIN history_stats AS hs ON hs.post_id = cp.id LEFT JOIN users AS u ON u.id = cp.owner_user_id ORDER BY hs.revision_count DESC, cp.score DESC LIMIT 100;
SELECT pl.id AS link_id, pl.link_type_id, pl.creation_date AS link_date, p.id AS source_post_id, p.post_title AS source_title, pu.display_name AS source_author, rp.id AS related_post_id, rp.post_title AS related_title, rpu.display_name AS related_author FROM posts AS p JOIN post_links AS pl ON pl.post_id = p.id JOIN posts AS rp ON rp.id = pl.related_post_id LEFT JOIN users AS pu ON pu.id = p.owner_user_id LEFT JOIN users AS rpu ON rpu.id = rp.owner_user_id WHERE p.creation_date >= '2009-04-01' AND p.creation_date < '2009-07-01' AND rp.creation_date >= '2009-04-01' AND rp.creation_date < '2009-10-01' ORDER BY pl.creation_date DESC LIMIT 100;
SELECT u.id, u.display_name, u.reputation, COUNT(*) AS question_count, SUM(p.score) AS total_score, AVG(p.view_count) AS avg_views FROM posts AS p JOIN users AS u ON u.id = p.owner_user_id WHERE p.post_type_id = 1 AND p.score >= 10 GROUP BY u.id, u.display_name, u.reputation HAVING COUNT(*) >= 3 ORDER BY total_score DESC LIMIT 100;